void LCD_ShowList(uint8_t index, uint8_t MaxNum)
{	
	uint16_t StartX = (240 - 24*MaxNum) >> 1;
	uint16_t StartY = 200;	
	int z;
	
	if(index == 0xFF) {
		for( z=0; z<MaxNum; z++ ) {			
			LCD_Clear_block(StartX, StartY, 12, 12, 0x0000);
			StartX += 24;
		}
		
		return;
	}
	
	for( z=0; z<MaxNum; z++ ) {
		if(z == index) 			
			LCD_ShowImg(StartX, StartY, 12, 12, (uint8_t*)_acdot_W);
		else			
			LCD_ShowImg(StartX, StartY, 12, 12, (uint8_t*)_acdot_G);
				
		StartX += 24;
	}
}


