void DisplayInit(void)
{
	struct LCD_frame frame = {{0,0},{239,239}};
	
	LCD_set_frame(frame);
	LCD_Clear_Screen(0x0000);
	ShowFlashIMG_ID(0);
	LCD_ShowList(0, 6);
}


/**
  * @brief  The application entry point.
  * @retval int
  */
int main(void)
{
	HAL_Init();
	SystemClock_Config();
		
	MX_GPIO_Init();
	MX_SPI1_Init();
	MX_SPI2_Init();
	
	LCD_init();
	Flash_Init();
	Encoder_Init();
			
	// == Write Image to Flash ====================
	BURNIMG();
	// ============================================
	
	// == Show Logo ===============================
	struct LCD_frame frame = {{0,0},{239,239}};	
	LCD_set_frame(frame);
	LCD_Clear_Screen(0xFFFF);
	ShowFlashIMG_ID(42);	
	LCD_BrightnessInit(BrightnessTable[Parm[3]]);
	HAL_Delay(3000);
	// ============================================
	
	Encoder2Index(&gCase, 5, 0, 0, 1);
	gCase = 0;
	ogCase = 0;
	DisplayInit();						// Initial Display Screen
		
	while (1) {
		Enocde_Process();
		
		if(gIndex.curreent_layer == 0) {
			Encoder2Index(&gCase, 5, 0, 0, 1);
			if(gCase != ogCase) {
				ShowFlashIMG_ID(gCase);
				LCD_ShowList(gCase, 6);
				ogCase = gCase;
			}
		}else {			
			switch(gCase) {
				case 0:	
					Encoder2Index(&Parm[gCase], ParmMax[gCase], ParmMin[gCase], 0, 0);
					FanParm(Parm[gCase]);
					break;
				
				case 1:
					Encoder2Index(&Parm[gCase], ParmMax[gCase], ParmMin[gCase], 0, 0);
					AirConditionerParm(Parm[gCase]);
					break;
				
				case 2:
					Encoder2Index(&Parm[gCase], ParmMax[gCase], ParmMin[gCase], 0, 0);
					TemperatureParm(Parm[gCase]);
					break;
				
				case 3:
					Encoder2Index(&Parm[gCase], ParmMax[gCase], ParmMin[gCase], 0, 0);
					BrightnessParm(Parm[gCase]);
					break;
				
				case 4:
					Encoder2Index(&Parm[gCase], ParmMax[gCase], ParmMin[gCase], 0, 0);
					AudioParm(Parm[gCase]);
					break;
				
				case 5:					
					break;
			}
		}
		
		// == §PÂ_SW«ö¤U ====================================
		if(HAL_GPIO_ReadPin(SW_Port, SW_Pin) == GPIO_PIN_RESET) {		
			gIndex.curreent_layer++;
			if(gIndex.curreent_layer > 1)
				gIndex.curreent_layer = 0;
			
			switch(gCase) {
				case 0:
					if(gIndex.curreent_layer == 1) {
						ReadIMGInfo_Flash(0, tmpInfo);
						LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);	
						LCD_ShowList(0xFF, 6);
						ShowFlashIMG_ID(7);
						FanRef = 0xFF;
						FanParm(Parm[gCase]);
					}else {
						struct LCD_frame frame = {{0,0},{239,239}};	
						LCD_set_frame(frame);
						LCD_Clear_Screen(0x0000);
						ShowFlashIMG_ID(0);
						LCD_ShowList(0, 6);
					}					
					break;
				
				case 1:
					if(gIndex.curreent_layer == 1) {
						ReadIMGInfo_Flash(1, tmpInfo);
						LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);	
						LCD_ShowList(0xFF, 6);
						ShowFlashIMG_ID(1);
						AirConditionerParm(Parm[gCase]);
					}else {
						struct LCD_frame frame = {{0,0},{239,239}};	
						LCD_set_frame(frame);
						LCD_Clear_Screen(0x0000);
						ShowFlashIMG_ID(1);
						LCD_ShowList(1, 6);
					}
					break;
				
				case 2:
					if(gIndex.curreent_layer == 1) {
						ReadIMGInfo_Flash(2, tmpInfo);
						LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);
						LCD_ShowList(0xFF, 6);
						ShowFlashIMG_ID(25);
						TemperatureRef = 0xFF;
						TemperatureParm(Parm[gCase]);
					}else {
						struct LCD_frame frame = {{0,0},{239,239}};	
						LCD_set_frame(frame);
						LCD_Clear_Screen(0x0000);
						ShowFlashIMG_ID(2);
						LCD_ShowList(2, 6);
					}
					break;
				
				case 3:
					if(gIndex.curreent_layer == 1) {
						ReadIMGInfo_Flash(3, tmpInfo);
						LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);
						LCD_ShowList(0xFF, 6);
						ShowFlashIMG_ID(34);
						BrightnessParm(Parm[gCase]);
					}else {
						struct LCD_frame frame = {{0,0},{239,239}};	
						LCD_set_frame(frame);
						LCD_Clear_Screen(0x0000);
						ShowFlashIMG_ID(3);
						LCD_ShowList(3, 6);
					}
					break;
				
				case 4:
					if(gIndex.curreent_layer == 1) {
						ReadIMGInfo_Flash(4, tmpInfo);
						LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);
						LCD_ShowList(0xFF, 6);
						ShowFlashIMG_ID(40);
						AudioParm(Parm[gCase]);
					}else {
						struct LCD_frame frame = {{0,0},{239,239}};	
						LCD_set_frame(frame);
						LCD_Clear_Screen(0x0000);
						ShowFlashIMG_ID(4);
						LCD_ShowList(4, 6);
					}
					break;
				
				case 5:
					if(gIndex.curreent_layer == 1)
						ShowFlashIMG_ID(6);						
					else 
						ShowFlashIMG_ID(5);
					
					LCD_ShowList(5, 6);
					
					break;
			}
			
			while(HAL_GPIO_ReadPin(SW_Port, SW_Pin) == GPIO_PIN_RESET);			
		}		
		// ==================================================
	}
}

