// ========================================================
//  ROM to SPI Flash 
// ========================================================
void ROM2FLASH(uint8_t ID, uint8_t x, uint8_t y, uint8_t w, uint8_t h, uint8_t *img)
{
	uint32_t Faddr;
	uint32_t Loop_cnt = 0;
	uint32_t Total_size;
	uint8_t *pt;
	
	#if defined(COLOR_SWAP)
	// == Âŕ´«Ľvął ========================
	uint8_t Itmp_buf[PAGE_SIZE];
	uint16_t cc;
	uint16_t ColorByte, ColorByte1;
	// ====================================	
	#endif
	
	Faddr = (uint32_t)ID * (uint32_t)IMG_SIZE;	
	
	// == Erase 64K Block * 2 ==============================
	Flash_EraseBlock(2*ID);
	Flash_EraseBlock(2*ID+1);	
	// =====================================================
	
	memset(Page_tmp, 0, sizeof(Page_tmp));
	Page_tmp[0] = x;
	Page_tmp[1] = y;
	Page_tmp[2] = w;
	Page_tmp[3] = h;
	Flash_Write((uint8_t*)Page_tmp, Faddr, 4);
	
	pt = img;
	Total_size = (uint32_t)w * (uint32_t)h * (uint32_t)2;
	Loop_cnt = 0;
	while(Total_size > 0) {
		if ( Total_size > PAGE_SIZE ) {
			Faddr = (uint32_t)ID * (uint32_t)IMG_SIZE + IMG_INFO + Loop_cnt * (uint32_t)PAGE_SIZE;
			#if defined(COLOR_SWAP)				
			// == Âŕ´«Ľvął ========================				
			for(cc=0; cc<PAGE_SIZE/2; cc++) {
				ColorByte = *(pt+(2*cc)) << 8 | *(pt+(2*cc+1));
				ColorByte1 = ((ColorByte & 0xFF00) >> 8) | ((ColorByte & 0x00FF) << 8);//((ColorByte & 0x07E0) >> 5) | ((ColorByte & 0xF800)) | ((ColorByte & 0x001F) << 6);				
				Itmp_buf[2*cc] = (uint8_t)((ColorByte1 & 0xFF00) >> 8);
				Itmp_buf[2*cc+1] = (uint8_t)(ColorByte1 & 0x00FF);
			}
			Flash_Write((uint8_t*)Itmp_buf, Faddr, PAGE_SIZE);
			// =====================================
			#else
			Flash_Write((uint8_t*)pt, Faddr, PAGE_SIZE);
			#endif
			
			Loop_cnt++;
			pt += PAGE_SIZE;
			Total_size -= PAGE_SIZE;
		}else {
			Faddr = (uint32_t)ID * (uint32_t)IMG_SIZE + IMG_INFO + Loop_cnt * (uint32_t)PAGE_SIZE;
			#if defined(COLOR_SWAP)
			// == Âŕ´«Ľvął ========================				
			for(cc=0; cc<Total_size/2; cc++) {
				ColorByte = *(pt+(2*cc)) << 8 | *(pt+(2*cc+1));
				ColorByte1 = ((ColorByte & 0xFF00) >> 8) | ((ColorByte & 0x00FF) << 8);//((ColorByte & 0x07E0) >> 5) | ((ColorByte & 0xF800)) | ((ColorByte & 0x001F) << 6);				
				Itmp_buf[2*cc] = (uint8_t)((ColorByte1 & 0xFF00) >> 8);
				Itmp_buf[2*cc+1] = (uint8_t)(ColorByte1 & 0x00FF);
			}
			Flash_Write((uint8_t*)Itmp_buf, Faddr, Total_size);
			// =====================================
			#else
			Flash_Write((uint8_t*)pt, Faddr, Total_size);
			#endif
			
			Total_size = 0;
		}
	}
}

// ========================================================
//  Read Flash Image Info
// ========================================================
void ReadIMGInfo_Flash(uint8_t ImageID, uint8_t *info)
{
	uint32_t gID;
	uint32_t gImageAddr;	
	
	gID = ImageID;
	gImageAddr = (uint32_t)gID * (uint32_t)IMG_SIZE;
	Flash_ReadBytes(info, gImageAddr, 4);
}

// ========================================================
//  Display Flash Image Data
// ========================================================
void ShowFlashIMG_ID(uint8_t ImageID)
{
	uint32_t gID;
	uint32_t gImageAddr;
	uint32_t gImageSize;
	uint32_t line;
	uint16_t gLine;
	uint32_t RealSize;
	
	gID = ImageID;
	gImageAddr = (uint32_t)gID * (uint32_t)IMG_SIZE;
	//FastRead(gImageAddr, Img_Info, 4);
	Flash_ReadBytes(Img_Info, gImageAddr, 4);
	//printf("\nImage Info. = 0x%x, 0x%x, 0x%x, 0x%x", Img_Info[0], Img_Info[1], Img_Info[2], Img_Info[3]);
		
	gImageAddr = (uint32_t)gID * (uint32_t)IMG_SIZE + PAGE_SIZE;
	gImageSize = (uint32_t)Img_Info[2] * (uint32_t)Img_Info[3] * (uint32_t)2;	
	gLine = 0;	
	//printf("\n Read Img Addr = 0x%x, Size = 0x%x", gImageAddr, gImageSize);

	while(gImageSize > 0) {
		if(gImageSize > 10240) {
			line = 10240 / (uint32_t)(Img_Info[2]<<1);
			RealSize = line * (Img_Info[2]<<1);			
			Flash_ReadBytes(Img_buf, gImageAddr, RealSize);
			
			LCD_ShowImg(Img_Info[0], Img_Info[1] + gLine, Img_Info[2], line, (uint8_t*)Img_buf);					
			gImageAddr += RealSize;
			gImageSize -= RealSize;
			gLine += line;
		}else {
			line = gImageSize / (uint32_t)(Img_Info[2]<<1);
			RealSize = line * (Img_Info[2]<<1);			
			Flash_ReadBytes(Img_buf, gImageAddr, RealSize);
					
			LCD_ShowImg(Img_Info[0], Img_Info[1] + gLine, Img_Info[2], line, (uint8_t*)Img_buf);
			gImageSize = 0;
		}
	}	
}

// ========================================================
//  Display Flash Image Data reference x/y
// ========================================================
void ShowFlashIMG_xy(uint8_t ImageID, uint8_t x, uint8_t y)
{
	uint32_t gID;
	uint32_t gImageAddr;
	uint32_t gImageSize;
	uint32_t line;
	uint16_t gLine;
	uint32_t RealSize;
	
	gID = ImageID;
	gImageAddr = (uint32_t)gID * (uint32_t)IMG_SIZE;
	Flash_ReadBytes(Img_Info, gImageAddr, 4);
	Img_Info[0] = x;
	Img_Info[1] = y;
		
	gImageAddr = (uint32_t)gID * (uint32_t)IMG_SIZE + PAGE_SIZE;
	gImageSize = (uint32_t)Img_Info[2] * (uint32_t)Img_Info[3] * (uint32_t)2;	
	gLine = 0;	

	while(gImageSize > 0) {
		if(gImageSize > 10240) {
			line = 10240 / (uint32_t)(Img_Info[2]<<1);
			RealSize = line * (Img_Info[2]<<1);
			Flash_ReadBytes(Img_buf, gImageAddr, RealSize);
			
			LCD_ShowImg(Img_Info[0], Img_Info[1] + gLine, Img_Info[2], line, (uint8_t*)Img_buf);					
			gImageAddr += RealSize;
			gImageSize -= RealSize;
			gLine += line;
		}else {
			line = gImageSize / (uint32_t)(Img_Info[2]<<1);
			RealSize = line * (Img_Info[2]<<1);			
			Flash_ReadBytes(Img_buf, gImageAddr, RealSize);
					
			LCD_ShowImg(Img_Info[0], Img_Info[1] + gLine, Img_Info[2], line, (uint8_t*)Img_buf);
			gImageSize = 0;
		}
	}	
}

// ==========================================================
//  ­·¶q§ÎşA˝ŐľăFunction
// ==========================================================
void FanParm(uint8_t v)
{
	int i;
	uint8_t index;	
	static const uint8_t addr[22][2] = {{ 46, 153},{ 40, 138},{ 38, 122},{ 38, 106},{ 41,  91},
	                                    { 47,  76},{ 55,  62},{ 66,  51},{ 79,  41},{ 93,  34},
	                                    {109,  30},{123,  30},{138,  34},{153,  41},{166,  51},
										{177,  62},{185,  76},{191,  91},{194, 106},{194, 122},
										{192, 138},{186, 153}};
	if(FanRef == 0xFF) {
		for(i=0; i<=v; i++) {
			if(i < 5)
				ShowFlashIMG_xy(8, addr[i][0], addr[i][1]);
			else if(i >= 5 && i < 15)
				ShowFlashIMG_xy(9, addr[i][0], addr[i][1]);
			else
				ShowFlashIMG_xy(10, addr[i][0], addr[i][1]);
		}
		FanRef = v;
	} else {
		if(FanRef > v) {
			index = FanRef;
			for(i=0; i<(FanRef-v); i++) {
				LCD_Clear_block(addr[index][0], addr[index][1], 10, 10, 0x0000);
				index--;
			}
		}else if(FanRef < v){
			for(i=0; i<=v; i++) {
				if(i < 5)
					ShowFlashIMG_xy(8, addr[i][0], addr[i][1]);
				else if(i >= 5 && i < 15)
					ShowFlashIMG_xy(9, addr[i][0], addr[i][1]);
				else
					ShowFlashIMG_xy(10, addr[i][0], addr[i][1]);
			}
		}
		FanRef = v;
	}										
}

