//  ŞĹ˝Ő§ÎşA˝ŐľăFunction
// ==========================================================
void AirConditionerParm(uint8_t v)
{
	//static uint8_t AirConditionerRef = 0xFF;
	
	ShowFlashIMG_ID(12+v);	
	//AirConditionerRef = v;								
}

// ==========================================================
//  ·Ĺ«×§ÎşA˝ŐľăFunction
// ==========================================================
void TemperatureParm(uint8_t v)
{
	int i;
	uint8_t index;	
	
	if(TemperatureRef == 0xFF) {
		for(i=0; i<=v; i++) 
			ShowFlashIMG_ID(26+i);	

		TemperatureRef = v;
	} else {
		if(TemperatureRef > v) {
			index = TemperatureRef;
			for(i=0; i<(TemperatureRef-v); i++) {
				ReadIMGInfo_Flash(26+index, tmpInfo);
				LCD_Clear_block(tmpInfo[0], tmpInfo[1], tmpInfo[2], tmpInfo[3], 0x0000);				
				index--;
			}
		}else if(TemperatureRef < v){
			for(i=0; i<=v; i++) 
				ShowFlashIMG_ID(26+i);	
		}
		TemperatureRef = v;
	}						
}

// ==========================================================
//  «G«×§ÎşA˝ŐľăFunction
// ==========================================================
void BrightnessParm(uint8_t v)
{	
	ShowFlashIMG_ID(35+v);	
	LCD_BrightnessSetting(BrightnessTable[v]);							
}

// ==========================================================
//  ­µ¶q§ÎşA˝ŐľăFunction
// ==========================================================
void AudioParm(uint8_t v)
{
	int i;
	uint8_t index;
	static uint8_t AudioRef = 0xFF;
	static const uint8_t audioxy[15][2] = {{  40, 161},{  51, 161},{  62, 161},{  73, 161},{  84, 161},
										   {  95, 161},{ 106, 161},{ 117, 161},{ 128, 161},{ 139, 161},
										   { 150, 161},{ 161, 161},{ 172, 161},{ 183, 161},{ 194, 161}};
	
	if(AudioRef == 0xFF) {
		for(i=0; i<=v; i++) 
			ShowFlashIMG_xy(41, audioxy[i][0], audioxy[i][1]);

		AudioRef = v;
	} else {
		if(AudioRef > v) {
			index = AudioRef;
			for(i=0; i<(AudioRef-v); i++) {
				LCD_Clear_block(audioxy[index][0], audioxy[index][1], 7, 24, 0x0000);				
				index--;
			}
		}else if(AudioRef < v){
			for(i=0; i<=v; i++) 
				ShowFlashIMG_xy(41, audioxy[i][0], audioxy[i][1]);
		}
		AudioRef = v;
	}						
}

